const data = $input.all()[0].json;
const doubts = data.doubts || [];
const count = data.escalated_count || 0;

let html = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">';
html += '<div style="background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%); color: white; padding: 30px; text-align: center; border-radius: 10px 10px 0 0;">';
html += '<h1 style="margin: 0;">🚨 Students Need Help!</h1>';
html += '</div>';
html += '<div style="background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;">';
html += `<p style="font-size: 16px; color: #333;"><strong>${count} topics</strong> have low AI confidence:</p>`;
html += '<ul style="list-style: none; padding: 0;">';
for (const d of doubts) {
  const confidence = (d.confidence * 100).toFixed(0);
  const emoji = d.confidence < 0.6 ? '🔴' : d.confidence < 0.7 ? '🟡' : '🟠';
  html += '<li style="background: white; margin: 10px 0; padding: 15px; border-left: 4px solid #f5576c; border-radius: 5px;">';
  html += `<strong style="color: #f5576c;">${emoji} ${d.topic || 'Unknown Topic'}</strong><br>`;
  html += `<span style="color: #666; font-size: 14px;">${d.message || d.doubt_text || 'No message'}</span><br>`;
  html += `<span style="color: #999; font-size: 12px;">Confidence: ${confidence}%</span>`;
  html += '</li>';
}
html += '</ul>';
html += '<div style="text-align: center; margin: 30px 0;">';
html += '<a href="http://localhost:3000/professor/escalations" style="display: inline-block; background: #f5576c; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; font-weight: bold;">Respond on DoubtMap</a>';
html += '</div>';
html += '</div>';
html += '</div>';
return [{ json: { emailBody: html, count: count, professor_email: 'professor@example.com' }}];
